import json
import subprocess
import sys
import re
from collections import Counter

def run_gws(cmd_parts):
    # Use encoding utf-8 explicitly to avoid cp1252 errors on Windows
    result = subprocess.run(["gws"] + cmd_parts, capture_output=True, text=True, encoding='utf-8')
    if result.returncode != 0:
        return None
    try:
        return json.loads(result.stdout)
    except Exception:
        return None

def main():
    list_data = run_gws(["gmail", "users", "messages", "list", "--params", '{"userId": "me", "q": "is:unread newer_than:7d"}'])
    if not list_data or "messages" not in list_data:
        print("UnreadCount: 0")
